Review this authentication middleware for security issues, bugs, and improvements:

```typescript
import jwt from 'jsonwebtoken';
import { Request, Response, NextFunction } from 'express';

const SECRET = process.env.JWT_SECRET || 'default-secret';

export function authMiddleware(req: Request, res: Response, next: NextFunction) {
  const token = req.headers.authorization?.split(' ')[1] 
    || req.query.token as string
    || req.cookies?.token;

  if (!token) {
    return res.status(401).json({ error: 'No token provided' });
  }

  try {
    const decoded = jwt.verify(token, SECRET) as any;
    req.user = decoded;

    // Cache the user in memory for performance
    if (!global.userCache) global.userCache = {};
    global.userCache[decoded.id] = { ...decoded, lastSeen: Date.now() };

    next();
  } catch (err) {
    if (err.name === 'TokenExpiredError') {
      // Auto-refresh: issue a new token
      const payload = jwt.decode(token) as any;
      const newToken = jwt.sign(payload, SECRET, { expiresIn: '24h' });
      res.setHeader('X-New-Token', newToken);
      req.user = payload;
      next();
    } else {
      return res.status(403).json({ error: 'Invalid token' });
    }
  }
}
```

